INSERT OR REPLACE INTO verses (id,work_id,division_id,ref,ordinal,devanagari,translit,uvaca,source_url) VALUES ('cb.adi.15.220','cb','cb.adi.15','ЧБ Ади 15.220',220,'বুদ্ধিমন্ত-খানে প্রভু দিলা আলিঙ্গন ।
তাহান আনন্দ অতি অকথ্য-কথন ॥২২০॥','буддхиманта-кха̄не прабху дила̄ а̄лин̇гана
та̄ха̄на а̄нанда ати акатхйа-катхана',NULL,NULL),('cb.adi.15.221','cb','cb.adi.15','ЧБ Ади 15.221',221,'এ সব লীলার কভু নাহি পরিচ্ছেদ ।
‘আবির্ভাব’ ‘তিরোভাব’ এই কহে বেদ ॥২২১॥','э саба лӣла̄ра кабху на̄хи париччхеда
‘а̄вирбха̄ва’ ‘тиробха̄ва’еи кахе веда',NULL,NULL),('cb.adi.15.222','cb','cb.adi.15','ЧБ Ади 15.222',222,'দণ্ডেকে এ সব লীলা যত হইয়াছে ।
শত-বর্ষে তাহা কে বর্ণিবে,—হেন আছে? ॥২২২॥','дан̣д̣аке э саба лӣла̄ йата хаийа̄чхе
ш́ата-варш̣е та̄ха̄ ке варн̣ибе, — хӣна а̄чхе?',NULL,NULL),('cb.adi.15.223','cb','cb.adi.15','ЧБ Ади 15.223',223,'নিত্যানন্দস্বরূপের আজ্ঞা ধরি’ শিরে ।
সুত্রমাত্র লিখি আমি কৃপা-অনুসারে ॥২২৩॥','нитйа̄нанда-сварӯпера а̄джн̃а̄ дхари’ ш́ире
сӯтра-ма̄тра ликхи а̄ми кр̣па̄-ануса̄ре',NULL,NULL),('cb.adi.15.224','cb','cb.adi.15','ЧБ Ади 15.224',224,'এ সব ঈশ্বর-লীলা যে পড়ে, যে শুনে ।
সে অবশ্য বিহরয়ে গৌরচন্দ্র-সনে ॥২২৪॥','э саба ӣш́вара-лӣла̄ йе пад̣е, йе ш́уне
се аваш́йа вихарайе гаурачандра-сане',NULL,NULL),('cb.adi.15.225','cb','cb.adi.15','ЧБ Ади 15.225',225,'শ্রীকৃষ্ণচৈতন্য-নিত্যানন্দচান্দ জান ।
বৃন্দাবনদাস তছু পদযুগে গান ॥২২৫॥','ш́рӣ кр̣ш̣н̣а-чаитанйа нитйа̄нанда-ча̄нда джа̄на
вр̣нда̄вана да̄са тачху пада-йуге га̄на',NULL,NULL),('cb.adi.16.1','cb','cb.adi.16','ЧБ Ади 16.1',1,'জয় জয় দীনবন্ধু শ্রীগৌরসুন্দর ।
জয় জয় লক্ষ্মীকান্ত সবার ঈশ্বর ॥১॥','джайа джайа дӣна-бандху ш́рӣ-гаурасундара
джайа джайа лакш̣мӣ-ка̄нта саба̄ра ӣш́вара',NULL,NULL),('cb.adi.16.2','cb','cb.adi.16','ЧБ Ади 16.2',2,'জয় জয় ভক্তরক্ষা-হেতু অবতার ।
জয় সর্ব্বকাল-সত্য কীর্ত্তন-বিহার ॥২॥','джайа джайа бхакта-ракш̣а̄ хету авата̄ра
джайа сарва-ка̄ла-сатйа кӣртана-виха̄ра',NULL,NULL),('cb.adi.16.3','cb','cb.adi.16','ЧБ Ади 16.3',3,'ভক্ত-গোষ্ঠী-সহিত গৌরাঙ্গ জয় জয় ।
শুনিলে চৈতন্য-কথা ভক্তি লভ্য হয় ॥৩॥','бхакта-гош̣т̣хӣ-сахита гаура̄н̇га джайа джайа
ш́униле чаитанйа-катха̄ бхакти лабхйа хайа',NULL,NULL),('cb.adi.16.4','cb','cb.adi.16','ЧБ Ади 16.4',4,'আদিখণ্ড-কথা অতি অমৃতের ধার ।
যহিঁ গৌরাঙ্গের সর্ব্বমোহন বিহার ॥৪॥','а̄ди-кхан̣д̣а-катха̄ ати амр̣тера дха̄ра
йахин̇ гаура̄н̇гера сарва-мохана виха̄ра',NULL,NULL),('cb.adi.16.5','cb','cb.adi.16','ЧБ Ади 16.5',5,'হেনমতে বৈকুণ্ঠ-নায়ক নবদ্বীপে ।
গৃহস্থ হইয়া পড়ায়েন দ্বিজরূপে ॥৫॥','хена-мате ваикун̣т̣ха-на̄йака навадвӣпе
гр̣хастха хаийа̄ пад̣а̄йена двиджа-рӯпе',NULL,NULL),('cb.adi.16.6','cb','cb.adi.16','ЧБ Ади 16.6',6,'প্রেমভক্তিপ্রকাশ-নিমিত্ত অবতার ।
তাহা কিছু না করেন, ইচ্ছা সে তাঁহার ॥৬॥','према-бхакти-прака̄ш́а нимитта авата̄ра
та̄ха̄ кичху на̄ карена, иччха̄ се та̄н̇ха̄ра',NULL,NULL),('cb.adi.16.7','cb','cb.adi.16','ЧБ Ади 16.7',7,'অতি পরমার্থশূন্য সকল সংসার ।
তুচ্ছরস-বিষয়ে সে আদর সবার ॥৭॥','ати парама̄ртха-ш́унйа сакала сам̇са̄ра
туччха-раса виш̣айе се а̄дара саба̄ра',NULL,NULL),('cb.adi.16.8','cb','cb.adi.16','ЧБ Ади 16.8',8,'গীতা ভাগবত বা পড়ায় যে-যে-জন ।
তারাও না বলে, না বলায় কৃষ্ণ-সঙ্কীর্ত্তন ॥৮॥','гӣта̄ бха̄гавата ва̄ пад̣а̄йа йе-йе-джана
та̄’ра̄ о на̄ бале, на̄ балайа кр̣ш̣н̣а-сан̇кӣртана',NULL,NULL),('cb.adi.16.9','cb','cb.adi.16','ЧБ Ади 16.9',9,'হাতে তালি দিয়া সে সকল ভক্তগণ ।
আপনা-আপনি মেলি’ করেন কীর্ত্তন ॥৯॥','ха̄те та̄ле дийа̄ се сакала бхакта-ган̣а
а̄пана̄-а̄пани мели’ карена кӣртана',NULL,NULL),('cb.adi.16.10','cb','cb.adi.16','ЧБ Ади 16.10',10,'তাহাতেও উপহাস করয়ে সবারে ।
“ইহারা কি কার্য্যে ডাক্ ছাড়ে উচ্চস্বরে ॥১০॥','та̄ха̄те о упаха̄са карайе саба̄ре
‘иха̄ра̄ ки ка̄рйе д̣а̄к чха̄д̣е уччасваре',NULL,NULL),('cb.adi.16.11','cb','cb.adi.16','ЧБ Ади 16.11',11,'আমি—ব্রহ্ম, আমাতেই বৈসে নিরঞ্জন ।
দাস-প্রভু-ভেদ বা করয়ে কি-কারণ?” ॥১১॥','а̄ми-брахма, а̄ма̄теи ваише ниран̃джана
да̄са-прабху-бхеда ва̄ карайе ки-ка̄ран̣а?’',NULL,NULL),('cb.adi.16.12','cb','cb.adi.16','ЧБ Ади 16.12',12,'সংসারী-সকল বলে,—“মাগিয়া খাইতে ।
ডাকিয়া বলয়ে ‘হরি’ লোক জানাইতে” ॥১২॥','сам̇са̄рӣ-сакала бале, — ‘ма̄гийа̄ кха̄ите
д̣а̄кийа̄ балайе ‘хари’ лока джа̄на̄ите’',NULL,NULL),('cb.adi.16.13','cb','cb.adi.16','ЧБ Ади 16.13',13,'“এ-গুলার ঘর-দ্বার ফেলাই ভাঙ্গিয়া” ।
এই যুক্তি করে সব-নদীয়া মিলিয়া ॥১৩॥','‘е-гула̄ра гхара-два̄ра пхела̄и бха̄н̇гийа̄’
эи йукти каре саба-надӣйа̄ милийа̄',NULL,NULL),('cb.adi.16.14','cb','cb.adi.16','ЧБ Ади 16.14',14,'শুনিয়া পায়েন দুঃখ সর্ব্ব-ভক্তগণে ।
সম্ভাষা করেন, হেন না পায়েন জনে ॥১৪॥','ш́унийа̄ па̄йена дух̣кха сарва-бхакта-ган̣е
самбха̄ш̣а̄ карена, хена на̄ па̄йена джане',NULL,NULL),('cb.adi.16.15','cb','cb.adi.16','ЧБ Ади 16.15',15,'শূন্য দেখি’ ভক্তগণ সকল-সংসার ।
‘হা কৃষ্ণ’ বলিয়া দুঃখ ভাবেন অপার ॥১৫॥','ш́ӯнйа декхи’ бхакта-ган̣а сакала-сам̇са̄ра
‘ха̄ кр̣ш̣н̣а’ балийа̄ дух̣кха бха̄вена апа̄ра',NULL,NULL),('cb.adi.16.16','cb','cb.adi.16','ЧБ Ади 16.16',16,'হেন কালে তথায় আইলা হরিদাস ।
শুদ্ধবিষ্ণুভক্তি যাঁর বিগ্রহে প্রকাশ ॥১৬॥','хена ка̄ле татха̄йа а̄ила̄ харида̄са
ш́уддха-виш̣н̣у-бхакти йа̄н̇’ра виграхе прака̄ш́а',NULL,NULL),('cb.adi.16.17','cb','cb.adi.16','ЧБ Ади 16.17',17,'এবে শুন হরিদাস-ঠাকুরের কথা ।
যাহার শ্রবণে কৃষ্ণ পাইবে সর্ব্বথা ॥১৭॥','эбе ш́уна харида̄са-т̣ха̄курера катха̄
йа̄ха̄ра ш́раван̣е кр̣ш̣н̣а па̄ибе сарватха̄',NULL,NULL),('cb.adi.16.18','cb','cb.adi.16','ЧБ Ади 16.18',18,'বুঢ়ন-গ্রামেতে অবতীর্ণ হরিদাস ।
সে-ভাগ্যে সে-সব দেশে কীর্ত্তন-প্রকাশ ॥১৮॥','буд̣ха̄на-гра̄мете аватӣрн̣а харида̄са
се-бха̄гйе се-саба деш́е кӣртана-прака̄ш́а',NULL,NULL),('cb.adi.16.19','cb','cb.adi.16','ЧБ Ади 16.19',19,'কতদিন থাকিয়া আইলা গঙ্গাতীরে ।
আসিয়া রহিলা ফুলিয়ায় শান্তিপুরে ॥১৯॥','ката-дина тха̄кийа̄ а̄ила̄ ган̇га̄-тӣре
а̄сийа̄ рахила̄ пхулийа̄йа ш́а̄нтипурӣ',NULL,NULL),('cb.adi.16.20','cb','cb.adi.16','ЧБ Ади 16.20',20,'পাইয়া তাহান সঙ্গ আচার্য্য-গোসাঞি ।
হুঙ্কার করেন, আনন্দের অন্ত নাই ॥২০॥','па̄ийа̄ та̄ха̄на сан̇га а̄ча̄рйа-госа̄н̃и
хун̇ка̄ра карена, а̄нандера анта на̄и',NULL,NULL),('cb.adi.16.20-2','cb','cb.adi.16','ЧБ Ади 16.20',20,'পাইয়া তাহান সঙ্গ আচার্য্য-গোসাঞি ।
হুঙ্কার করেন, আনন্দের অন্ত নাই ॥২০॥','па̄ийа̄ та̄ха̄на сан̇га а̄ча̄рйа-госа̄н̃и
хун̇ка̄ра карена, а̄нандера анта на̄и',NULL,NULL),('cb.adi.16.21','cb','cb.adi.16','ЧБ Ади 16.21',21,'হরিদাস-ঠাকুরো অদ্বৈতদেব-সঙ্গে ।
ভাসেন গোবিন্দরস-সমুদ্র-তরঙ্গে ॥২১॥','харида̄са-т̣ха̄кур о адваита-дева-сан̇ге
бха̄сена говинда-раса-самудра-таран̇ге',NULL,NULL),('cb.adi.16.22','cb','cb.adi.16','ЧБ Ади 16.22',22,'নিরবধি হরিদাস গঙ্গা-তীরে-তীরে ।
ভ্রমেন কৌতুকে ‘কৃষ্ণ’ বলি’ উচ্চস্বরে ॥২২॥','наравадхи харида̄са ган̇га̄-тӣре-тӣре
бхрамен̣а каутуке ‘кр̣ш̣н̣а’ бали’ уччашваре',NULL,NULL),('cb.adi.16.23','cb','cb.adi.16','ЧБ Ади 16.23',23,'বিষয়-সুখেতে বিরক্তের অগ্রগণ্য ।
কৃষ্ণনামে পরিপূর্ণ শ্রীবদন ধন্য ॥২৩॥','виш̣айа-сукхете вирактера аграган̣йа
кр̣ш̣н̣а-на̄ме парипӯрн̣а ш́рӣ-вадана дханйа',NULL,NULL),('cb.adi.16.24','cb','cb.adi.16','ЧБ Ади 16.24',24,'ক্ষণেক গোবিন্দ-নামে নাহিক বিরক্তি ।
ভক্তিরসে অনুক্ষণ হয় নানা-মূর্ত্তি ॥২৪॥','кш̣ан̣ека говинда-на̄ме на̄хика виракти
бхакти-расе анукш̣ан̣а хайа на̄на̄ мӯрти',NULL,NULL),('cb.adi.16.25','cb','cb.adi.16','ЧБ Ади 16.25',25,'কখনো করেন নৃত্য আপনা-আপনি ।
কখনো করেন মত্তসিংহ-প্রায় ধ্বনি ॥২৫॥','какхано карена нр̣тйа а̄пана̄-а̄пани
какхано карена матта-сим̇ха-пра̄йа дхвани',NULL,NULL),('cb.adi.16.26','cb','cb.adi.16','ЧБ Ади 16.26',26,'কখনো বা উচ্চৈঃস্বরে করেন রোদন ।
অট্ট-অট্ট মহা-হাস্য হাসেন কখন ॥২৬॥','какхано ва̄ уччаих̣сваре карена родана
ат̣т̣а-ат̣т̣а маха̄-ха̄сйа ха̄сена какхана',NULL,NULL),('cb.adi.16.27','cb','cb.adi.16','ЧБ Ади 16.27',27,'কখনো গর্জ্জেন অতি হুঙ্কার করিয়া ।
কখনো মূর্চ্ছিত হই’ থাকেন পড়িয়া ॥২৭॥','какхано гарджджена ати хун̇ка̄ра карийа̄
какхано мӯрччхита хаи’ тха̄кена пад̣ийа̄',NULL,NULL),('cb.adi.16.28','cb','cb.adi.16','ЧБ Ади 16.28',28,'ক্ষণে অলৌকিক শব্দ বলেন ডাকিয়া ।
ক্ষণে তাই বাখানেন উত্তম করিয়া ॥২৮॥','кш̣ан̣е алаукика ш́абда балена да̄кийа̄
кш̣ан̣е та̄и ва̄кха̄нена уттама карийа̄',NULL,NULL),('cb.adi.16.29','cb','cb.adi.16','ЧБ Ади 16.29',29,'অশ্রুপাত, রোমহর্ষ, হাস্য, মূর্চ্ছা, ঘর্ম্ম ।
কৃষ্ণভক্তি-বিকারের যত আছে মর্ম্ম ॥২৯॥','аш́рупа̄та, ромахарш̣а, ха̄сйа, мӯрччха̄, гхарма
кр̣ш̣н̣а-бхакти-вика̄рера йата а̄чхе марма',NULL,NULL),('cb.adi.16.30','cb','cb.adi.16','ЧБ Ади 16.30',30,'প্রভু হরিদাস মাত্র নৃত্যে প্রবেশিলে ।
সকল আসিয়া তান শ্রীবিগ্রহে মিলে ॥৩০॥','прабху харида̄са ма̄тра нр̣тйе правеш́иле
сакала а̄сийа̄ та̄’на ш́рӣ-виграхе миле',NULL,NULL),('cb.adi.16.31','cb','cb.adi.16','ЧБ Ади 16.31',31,'হেন সে আনন্দ-ধারা, তিতে সর্ব্ব-অঙ্গ ।
অতি-পাষণ্ডীও দেখি’ পায় মহারঙ্গ ॥৩১॥','хена се а̄нанда-дха̄ра̄, тите сарва-ан̇га
ати-па̄ш̣ан̣д̣ӣ о декхи’ па̄йа маха̄-ран̇га',NULL,NULL),('cb.adi.16.32','cb','cb.adi.16','ЧБ Ади 16.32',32,'কিবা সে অদ্ভুত অঙ্গে শ্রীপুলকাবলি ।
ব্রহ্মা-শিবও দেখিয়া হয়েন কুতূহলী ॥৩২॥','киба̄ се адбхута ан̇ге ш́рӣ-пулака̄вали
